app = Flask(__name__)


@app.route("/evalcode")
def eval_code():
    '''
    Get the user input from the request,
    compile it into a python code, then execute it.
    '''
    # SECURITY: Executing arbitrary user-supplied code (eval/exec) is a
    # critical vulnerability (CWE-94: Improper Control of Generation of Code).
    # There is no safe way to "compile and execute" untrusted input, so we
    # refuse to do so and only support a fixed whitelist of safe operations.

    import ast
    import operator

    user_input = request.args.get("code", "")

    if not user_input:
        return "No code provided", 400

    # Only allow evaluation of simple, safe arithmetic expressions.
    allowed_binops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }
    allowed_unaryops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def safe_eval(node):
        if isinstance(node, ast.Expression):
            return safe_eval(node.body)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Only numeric constants are allowed")
        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in allowed_binops:
                raise ValueError("Operator not allowed")
            left = safe_eval(node.left)
            right = safe_eval(node.right)
            # Prevent excessively large exponentiation (DoS).
            if op_type is ast.Pow and isinstance(right, int) and right > 100:
                raise ValueError("Exponent too large")
            return allowed_binops[op_type](left, right)
        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in allowed_unaryops:
                raise ValueError("Operator not allowed")
            return allowed_unaryops[op_type](safe_eval(node.operand))
        raise ValueError("Expression element not allowed")

    try:
        parsed = ast.parse(user_input, mode="eval")
        result = safe_eval(parsed)
    except Exception:
        return "Invalid or disallowed expression", 400

    return str(result)


