from flask import Flask, request
import importlib

app = Flask(__name__)

# Whitelist of allowed module versions to prevent code injection
ALLOWED_VERSIONS = {'2', '3'}


@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    version = request.args.get('version', '')

    # Validate the version against a strict whitelist to avoid
    # passing untrusted input into exec() (CWE-94: Code Injection).
    if version not in ALLOWED_VERSIONS:
        return "Invalid version", 400

    # Map validated versions to fixed, safe module names.
    module_map = {
        '2': 'urllib',
        '3': 'urllib.request',
    }
    module_name = module_map[version]

    try:
        # Use importlib instead of exec for safe, dynamic imports.
        module = importlib.import_module(module_name)
    except ImportError:
        return "Module not available", 500

    return f"Imported {module.__name__}"


if __name__ == '__main__':
    app.run()

