import pickle


# Whitelist of safe types that are allowed to be unpickled.
_SAFE_BUILTINS = {
    "builtins": {"dict", "list", "tuple", "set", "frozenset", "str",
                 "bytes", "int", "float", "bool", "complex", "NoneType"},
}


class _RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that prevents arbitrary code execution
    (CWE-502) by only allowing a small whitelist of safe built-in types.
    """

    def find_class(self, module, name):
        allowed = _SAFE_BUILTINS.get(module)
        if allowed and name in allowed:
            return super().find_class(module, name)
        raise pickle.UnpicklingError(
            "Attempt to unpickle disallowed type %s.%s" % (module, name)
        )


def _safe_loads(data):
    return _RestrictedUnpickler(io.BytesIO(data)).load()


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    if not headers:
        return None

    # Retrieve the token from the headers.
    try:
        raw_token = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw_token:
        return None

    # Base64-decode the token safely.
    try:
        if isinstance(raw_token, str):
            raw_token = raw_token.encode('utf-8')
        decoded = base64.b64decode(raw_token, validate=True)
    except Exception:
        return None

    # Deserialize using a restricted unpickler to avoid arbitrary
    # code execution from untrusted input.
    try:
        token = _safe_loads(decoded)
    except Exception:
        return None

    # Validate the token structure and contents.
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

import base64
import binascii
import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    if not headers:
        return None

    # Retrieve the token from the headers.
    try:
        raw_token = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw_token:
        return None

    # Base64-decode the token safely.
    try:
        if isinstance(raw_token, str):
            raw_token = raw_token.encode('utf-8')
        decoded = base64.b64decode(raw_token, validate=True)
    except (binascii.Error, ValueError):
        return None

    # Deserialize using JSON to avoid arbitrary code execution
    # from untrusted input (CWE-502).
    try:
        token = json.loads(decoded.decode('utf-8'))
    except (ValueError, UnicodeDecodeError):
        return None

    # Validate the token structure and contents.
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

